    <script>
        function clearErrors() {
            $("".text-danger"").text("""");
            $("".form-control, .form-select"").removeClass(""is-invalid"");
        }

        function setError(inputId, errorId, message) {
            if (inputId !== """") {
                $(""#"" + inputId).addClass(""is-invalid"");
            }
            $(""#"" + errorId).text(message);
        }

        // 🔥 Medicine Name special character control
        $(""#MedicineName"").on(""input"", function () {
            let value = $(this).val();
            value = value.replace(/[^a-zA-Z0-9 +\-\/]/g, '');
            $(this).val(value);
        });

        $(""#medicineForm"").on(""submit"", function (e) {

            clearErrors();
            let isValid = true;

            // 🔥 Medicine Name (updated)
            let medName = $(""#MedicineName"").val().trim();
            if (medName === """") {
                setError(""MedicineName"", ""errMedicineName"", ""Medicine Name is required"");
             ");
                WriteLiteral(@"   isValid = false;
            } else if (!/^[a-zA-Z0-9 +\-\/]+$/.test(medName)) {
                setError(""MedicineName"", ""errMedicineName"", ""Invalid characters in medicine name"");
                isValid = false;
            }

            // Type
            if ($(""#Type"").val().trim() === """") {
                setError(""Type"", ""errType"", ""Please select medicine type"");
                isValid = false;
            }

            // Quantity
            let qty = parseInt($(""#Quantity"").val(), 10);
            if (isNaN(qty) || qty < 1) {
                setError(""Quantity"", ""errQuantity"", ""Quantity must be greater than 0"");
                isValid = false;
            }

            // Description
            if ($(""#Description"").val().trim() === """") {
                setError(""Description"", ""errDescription"", ""Description is required"");
                isValid = false;
            }

            // Schedule
            if (
                !$(""#Morning"").is("":checked"") &&
   ");
                WriteLiteral(@"             !$(""#Afternoon"").is("":checked"") &&
                !$(""#Evening"").is("":checked"")
            ) {
                setError("""", ""errSchedule"", ""Select at least one schedule (Morning / Afternoon / Evening)"");
                isValid = false;
            }

            if (!isValid) {
                e.preventDefault();
            }
        });

    </script>
");
